select d1.v,d2.PARAM_NAME,TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') as recordTime from tth.DAY_WATER_SITUATION_STATISTICS_TABLE_QS d1 left join tth.TRENDS_TABLE_PARAM d2 on d1.TABLE_HEAD_ID = d2.id
and d1.TABLE_HEAD_ID in
#{item}
and TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') between #{req.startTime} and #{req.endTime}
and d1.TIME = '今日均'

select ID,RECORD_TIME,TIME,TABLE_HEAD_ID,V,FRONT_TABLE_LIST,END_TABLE_LIST
from DAY_WATER_SITUATION_STATISTICS_TABLE_QS


        and TABLE_HEAD_ID not in

            #{item}



        and TO_CHAR(RECORD_TIME,'YYYY-MM-DD') between #{startTime} and #{endTime}

    and TIME = '今日均'

select RECORD_TIME,TABLE_HEAD_ID,V
from DAY_WATER_SITUATION_STATISTICS_TABLE_QS


        and TABLE_HEAD_ID in

            #{item}



        and TO_CHAR(RECORD_TIME,'YYYY-MM-DD') between #{startTime} and #{endTime}

    and TIME = '今日均'

select ID,RECORD_TIME,TIME,TABLE_HEAD_ID,V,FRONT_TABLE_LIST,END_TABLE_LIST
from DAY_WATER_SITUATION_STATISTICS_TABLE_QS


        and TABLE_HEAD_ID in

            #{item}



        and TO_CHAR(RECORD_TIME,'YYYY-MM-DD') between #{startTime} and #{endTime}

    and TIME = '今日均'

select d1.v,d2.PARAM_NAME,TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') as recordTime,d1.TIME
from tth.DAY_WATER_SITUATION_STATISTICS_TABLE_QS d1
left join tth.TRENDS_TABLE_PARAM d2 on d1.TABLE_HEAD_ID = d2.id


        and d1.TABLE_HEAD_ID = #{req.ids[0]}


        and TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') between #{req.startTime} and #{req.endTime}

    and  d1.TIME != '今日均' and d1.TIME != '昨日均'
    and d1.v = (
    select d1.v
    from tth.DAY_WATER_SITUATION_STATISTICS_TABLE_QS d1
    left join tth.TRENDS_TABLE_PARAM d2 on d1.TABLE_HEAD_ID = d2.id


            and d1.TABLE_HEAD_ID = #{req.ids[0]}


            and TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') between #{req.startTime} and #{req.endTime}

        and  d1.TIME != '今日均' and d1.TIME != '昨日均' and d1.v is not null
        order by d1.v desc limit 1

    )

select d1.v,d2.PARAM_NAME,TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') as recordTime,d1.TIME
from tth.DAY_WATER_SITUATION_STATISTICS_TABLE_QS d1
left join tth.TRENDS_TABLE_PARAM d2 on d1.TABLE_HEAD_ID = d2.id


        and d1.TABLE_HEAD_ID = #{req.ids[0]}


        and TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') between #{req.startTime} and #{req.endTime}

    and  d1.TIME != '今日均' and d1.TIME != '昨日均'
    and d1.v = (
    select d1.v
    from tth.DAY_WATER_SITUATION_STATISTICS_TABLE_QS d1
    left join tth.TRENDS_TABLE_PARAM d2 on d1.TABLE_HEAD_ID = d2.id


            and d1.TABLE_HEAD_ID = #{req.ids[0]}


            and TO_CHAR(d1.RECORD_TIME,'YYYY-MM-DD') between #{req.startTime} and #{req.endTime}

        and  d1.TIME != '今日均' and d1.TIME != '昨日均' and d1.v is not null
        order by d1.v asc limit 1

    )
